#include <stdio.h>
#include <stdlib.h>

struct Node {
    int data;
    struct Node *next;
};

struct Node* insertAtBeginning(struct Node *head, int value) {
    struct Node *newNode = (struct Node *)malloc(sizeof(struct Node));
    newNode->data = value;
    newNode->next = head;
    return newNode;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, X;
        scanf("%d", &N);
        int *arr = (int *)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) {
            scanf("%d", &arr[i]);
        }
        scanf("%d", &X);
        // Build list by inserting at head (reverse order)
        struct Node *head = NULL;
        for (int i = 0; i < N; ++i) {
            head = insertAtBeginning(head, arr[i]);
        }
        head = insertAtBeginning(head, X);
        for (struct Node *cur = head; cur; cur = cur->next) {
            printf("%d", cur->data);
            if (cur->next) printf(" ");
        }
        printf("\n");
        // free memory
        while (head) {
            struct Node *tmp = head;
            head = head->next;
            free(tmp);
        }
        free(arr);
    }
    return 0;
}

