#include <bits/stdc++.h>
using namespace std;

struct Node {
    int data;
    Node *next;
    Node(int v, Node *n = nullptr) : data(v), next(n) {}
};

Node* insertAtBeginning(Node *head, int value) {
    return new Node(value, head);
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin >> T)) return 0;
    while (T--) {
        int N, X; cin >> N;
        vector<int> a(N);
        for (int i = 0; i < N; ++i) cin >> a[i];
        cin >> X;
        Node *head = nullptr;
        for (int i = 0; i < N; ++i) {
            head = insertAtBeginning(head, a[i]);
        }
        head = insertAtBeginning(head, X);
        for (Node *cur = head; cur; cur = cur->next) {
            cout << cur->data;
            if (cur->next) cout << ' ';
        }
        cout << '\n';
        while (head) {
            Node *tmp = head;
            head = head->next;
            delete tmp;
        }
    }
    return 0;
}

